mapper.update:
UPDATE tb_order
SET total_price = #{totalPrice},
    order_status = #{orderStatus},
    last_edit_time = #{lastEditTime}
WHERE order_id = #{orderId}

UPDATE tb_order_item
SET quantity = #{quantity},
    total_price = #{totalPrice}
WHERE order_item_id = #{orderItemId}

UPDATE tb_product SET product_locked_number = product_locked_number + #{quantity},
        product_number = product_number - #{quantity}
WHERE product_number - #{quantity} > 0 AND product_id = #{product.productId}

UPDATE tb_product SET product_locked_number = product_locked_number - #{quantity},
                      sales_volume = sales_volume + #{quantity}
WHERE product_id = #{product.productId}

UPDATE tb_product SET product_locked_number = product_locked_number - #{quantity},
        product_number = product_number + #{quantity}
WHERE product_id = #{product.productId}

mapper.select:
SELECT o.order_id, oi.order_item_id, oi.quantity, oi.product_id FROM tb_order o
    LEFT JOIN tb_order_item oi on o.order_id = oi.order_id
WHERE o.order_id = #{orderId}
